SELECT DISTINCT user_id
FROM daily_logs
WHERE date BETWEEN '2023-05-01' AND '2023-05-07';

SELECT AVG(weight) AS average_weight
FROM weight_logs
WHERE user_id = 0;

SELECT total_calories
FROM daily_logs
WHERE user_id = 1 AND date = '2023-05-02';

SELECT AVG(pm_stress) AS average_evening_stress
FROM daily_logs
WHERE user_id = 1;

SELECT DISTINCT dl.user_id
FROM daily_logs dl
WHERE dl.date BETWEEN '2023-05-01' AND '2023-05-02';

SELECT username
FROM users
WHERE user_id NOT IN (SELECT user_id FROM goals);
